registerDebugTool(
  "codex_choose_tool",
  {
    title: "Choose Codex tool",
    description: "Debug helper for choosing a Codex MCP tool. Hidden by default; Claude normally chooses among codex_task, codex_task_group, and codex_followup directly.",
    inputSchema: {
      request: external_exports.string().trim().optional().describe("Optional user request Claude is trying to map to a Codex tool."),
      task_count: external_exports.number().int().min(1).max(24).optional().describe("Known number of independent Codex tasks."),
      wants_parallel: external_exports.boolean().optional().describe("Whether the user asked for parallel or multiple Codex agents."),
      wants_session: external_exports.boolean().optional().describe("Whether the user asked for Codex to keep context across prompts."),
      continuing_session: external_exports.boolean().optional().describe("Whether Claude already has a Codex session id to continue."),
      wants_async_session: external_exports.boolean().optional().describe("Whether Claude needs a Codex session id immediately while work continues."),
      wants_steering: external_exports.boolean().optional().describe("Whether the user wants to steer or redirect an already-running Codex session."),
      recovering_after_restart: external_exports.boolean().optional().describe("Whether Claude has a persisted session id from before an MCP/Claude restart."),
      long_running: external_exports.boolean().optional().describe("Whether the work is likely to exceed a normal MCP request timeout."),
      wants_aggregation: external_exports.boolean().optional().describe("Whether Claude needs a deterministic consensus object.")
    }
  },
  async (args, extra) => loggedToolCall("codex_choose_tool", args, extra, async () => {
    const taskCount = args.task_count ?? (args.wants_parallel ? 2 : 1);
    let recommendedTool = "codex_task";
    if (args.wants_steering || args.continuing_session || args.recovering_after_restart) recommendedTool = "codex_followup";
    else if (args.wants_session || args.long_running) recommendedTool = "codex_task";
    else if (args.wants_aggregation) recommendedTool = "codex_task_group";
    else if (args.wants_parallel || taskCount > 1) recommendedTool = "codex_task_group";
    return jsonResult({
      recommendedTool,
      request: args.request,
      rules: [
        "Use codex_task when Claude wants an independent Codex frontier-model second opinion, deep technical subagent, complex codebase review, server/deployment investigation, or adversarial validation.",
        "Use multiple codex_task calls for ordinary independent parallel work; use codex_task_group when Claude wants one combined rollup.",
        "Use codex_followup for follow-ups, waits, cancellation, and steering when Claude has a session_id.",
        "Use codex_wait_any when Claude has several background Codex session_ids and wants to harvest results as they finish.",
        "Use codex_task with background true for slow work that should not hold a blocking request open.",
        "Use codex_task_group when Claude needs multiple independent answers returned as one merged response.",
        "Pass project_dir whenever Claude knows the active project directory.",
        "Do not use Codex for simple file reads, simple grep/search, or tiny commands Claude can do directly.",
        "When error.kind is backpressure, inspect codex://status and retry with less parallelism after a short wait.",
        "Do not use Bash or Read to locate Codex; this MCP server resolves the binary."
      ],
      legacyCompatibility: "Debug and pre-refactor tools are disabled by default. Set CODEX_SUBAGENTS_ENABLE_DEBUG_TOOLS=1 or CODEX_SUBAGENTS_ENABLE_LEGACY_TOOLS=1 only for diagnostics or older clients/tests."
    });
  })
);
registerTool(
  "codex_task",
  {
    title: "Task",
    description: "Use this when you want an independent OpenAI Codex frontier-model subagent: a technical second opinion, deep complex-codebase work, server/deployment investigation, difficult debugging, or adversarial review. This is the Codex equivalent of native Task. It does not share Claude's scratchpad, defaults to read-only, and returns an answer-first result. Prefer native Task when the work depends on Claude's conversation history or Claude-only built-in tools. Use multiple parallel codex_task calls when investigations are independent.",
    inputSchema: {
      description: external_exports.string().trim().min(1).describe("Short human-readable task label, like Claude's native Task description."),
      prompt: external_exports.string().trim().min(1).describe(
        "Self-contained Codex task prompt. Include scope, read-only expectation, output shape, and file/line reference requirements when reviewing code."
      ),
      subagent_type: external_exports.enum(codexRoleSchema.options).optional().describe("Claude-style Codex persona. Prefer general-purpose, explorer, planner, code-reviewer, or security-reviewer. Defaults to general-purpose."),
      background: external_exports.boolean().default(false).describe("Equivalent to native run_in_background: return immediately with a session_id while Codex keeps working."),
      keep_session: external_exports.boolean().default(false).describe("Return session_id after a completed task so Claude can continue this Codex context. Leave false for one-shot native Task-like work."),
      session_name: external_exports.string().trim().min(1).optional().describe("Optional human label for the returned Codex session."),
      ...nativeBaseInputSchema
    }
  },
  async (args, extra) => {
    return loggedToolCall("codex_task", args, extra, async () => {
      const progress = createProgressReporter(extra);
      try {
        const runOptions = {
          ...publicRunOptions(args),
          ephemeral: false
        };
        await progress.send(`Starting Codex task: ${args.description}`);
        if (args.background || args.advanced?.wait_for_completion === false) {
          throwIfRequestAborted(extra);
          const { session: session2, turn } = sessionManager.startAsync(runOptions, { sessionName: args.session_name });
          await progress.flush();
          const compactSession2 = compactSessionSnapshotForMcp(session2);
          const payload = {
            ok: true,
            status: "running",
            summary: `Started Codex task: ${args.description}`,
            result: `Codex task started in the background. Session: ${session2.id}`,
            session_id: session2.id,
            turn,
            hint: "Use codex_wait_any for parallel background tasks, or codex_followup mode wait, steer, or cancel with this session_id."
          };
          if (args.advanced?.include_diagnostics) {
            payload.diagnostics = {
              session: compactSession2,
              ...sessionProgressPayload(compactSession2)
            };
          }
          return nativeTextResult(payload);
        }
        const { session, result } = await withProgressHeartbeat(
          progress,
          `Still running Codex task: ${args.description}`,
          () => sessionManager.start(withRequestAbort(runOptions, extra), {
            sessionName: args.session_name,
            onMilestone: (milestone) => {
              const message = formatMilestoneProgress(milestone);
              if (message) void progress.send(message);
            }
          })
        );
        await reportAgentResult(progress, result);
        await progress.flush();
        const compactSession = compactSessionSnapshotForMcp(session);
        return nativeAgentResponse(result, {
          description: args.description,
          prompt: args.prompt,
          tool: "codex_task",
          session: compactSession,
          turn: compactSession.recentTurns?.at(-1),
          includeDiagnostics: Boolean(args.advanced?.include_diagnostics),
          includeSessionId: Boolean(args.keep_session)
        });
      } catch (error2) {
        await progress.flush();
        logger.error("codex_task.failed", { error: errorForLog(error2) });
        return nativeErrorResult(error2, "codex_task");
      }
    });
  }
);
