registerDebugTool(
  "codex_session_wait",
  {
    title: "Codex Session Wait",
    description: "Wait until a Codex session becomes idle, or until a specific queued/running turn completes. Use after codex_session_start, codex_session_prompt, or codex_session_steer.",
    inputSchema: {
      session_id: sessionIdSchema,
      turn_id: external_exports.string().trim().min(1).optional().describe("Optional turn id to wait for. Omit to wait until the whole session queue is idle."),
      timeout_ms: external_exports.number().int().positive().max(864e5).default(6e5)
    }
  },
  async (args, extra) => loggedToolCall("codex_session_wait", args, extra, async () => {
    const progress = createProgressReporter(extra);
    try {
      await progress.send(`Waiting for Codex session ${args.session_id}`);
      const waited = await withProgressHeartbeat(
        progress,
        `Still waiting for Codex session ${args.session_id}`,
        () => sessionManager.wait(args.session_id, args.timeout_ms, args.turn_id, extra?.signal)
      );
      await progress.flush();
      if (waited.error || !waited.session) {
        return errorResult(new Error(waited.error ?? "Codex session was not found."), "codex_session_wait");
      }
      const compactSession = compactSessionSnapshotForMcp(waited.session);
      const recovery = recoveryForWait("codex_session", waited.timeoutReason);
      return jsonResult({
        ok: waited.timeoutReason !== "wait_cancelled",
        completed: waited.completed,
        timeoutReason: waited.timeoutReason,
        session: compactSession,
        ...sessionProgressPayload(compactSession),
        turn: waited.turn,
        recovery,
        suggested_next_action: recovery?.recommendedAction,
        next_action: recovery?.recommendedAction ?? "Use session.lastResult directly, or send a follow-up prompt if more Codex context is needed."
      }, waited.timeoutReason === "wait_cancelled");
    } catch (error2) {
      await progress.flush();
      logger.error("codex_session_wait.failed", { error: errorForLog(error2) });
      return errorResult(error2, "codex_session_wait");
    }
  })
);
